extension WebViewController: WKScriptMessageHandler {
    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        guard let body = message.body as? [String: Any] else { return }
        
        switch message.name {
        case "camera":
            handleCameraRequest(body)
        case "pushNotifications":
            handlePushNotificationRequest(body)
        case "inAppPurchase":
            handleInAppPurchaseRequest(body)
        case "nativeLog":
            handleNativeLog(body)
        default:
            break
        }
    }
    
    private func handleCameraRequest(_ data: [String: Any]) {
        guard let action = data["action"] as? String else { return }
        
        switch action {
        case "checkPermission":
            checkCameraPermission()
        case "requestPermission":
            requestCameraPermission()
        case "openCamera":
            openCamera()
        default:
            break
        }
    }
    
    private func checkCameraPermission() {
        let status = AVCaptureDevice.authorizationStatus(for: .video)
        let permissionStatus: String
        
        switch status {
        case .authorized:
            permissionStatus = "granted"
        case .denied, .restricted:
            permissionStatus = "denied"
        case .notDetermined:
            permissionStatus = "notDetermined"
        @unknown default:
            permissionStatus = "unknown"
        }
        
        sendMessageToWeb(type: "cameraPermission", data: ["status": permissionStatus])
    }
    
    private func requestCameraPermission() {
        AVCaptureDevice.requestAccess(for: .video) { [weak self] granted in
            DispatchQueue.main.async {
                self?.sendMessageToWeb(type: "cameraPermission", data: ["status": granted ? "granted" : "denied"])
            }
        }
    }
    
    private func openCamera() {
        let status = AVCaptureDevice.authorizationStatus(for: .video)
        guard status == .authorized else {
            sendMessageToWeb(type: "cameraError", data: ["error": "Permission not granted"])
            return
        }
        
        guard UIImagePickerController.isSourceTypeAvailable(.camera) else {
            sendMessageToWeb(type: "cameraError", data: ["error": "Camera not available"])
            return
        }
        
        DispatchQueue.main.async { [weak self] in
            let picker = UIImagePickerController()
            picker.sourceType = .camera
            picker.delegate = self
            picker.allowsEditing = false
            self?.present(picker, animated: true)
        }
    }
    
    private func handlePushNotificationRequest(_ data: [String: Any]) {
        guard let action = data["action"] as? String else { return }
        
        switch action {
        case "checkPermission":
            checkNotificationPermission()
        case "requestPermission":
            requestNotificationPermission()
        case "getToken":
            getDeviceToken()
        default:
            break
        }
    }
    
    private func checkNotificationPermission() {
        UNUserNotificationCenter.current().getNotificationSettings { [weak self] settings in
            let status: String
            switch settings.authorizationStatus {
            case .authorized, .provisional:
                status = "granted"
            case .denied:
                status = "denied"
            case .notDetermined:
                status = "notDetermined"
            case .ephemeral:
                status = "ephemeral"
            @unknown default:
                status = "unknown"
            }
            
            DispatchQueue.main.async {
                self?.sendMessageToWeb(type: "notificationPermission", data: ["status": status])
            }
        }
    }
    
    private func requestNotificationPermission() {
        UNUserNotificationCenter.current().requestAuthorization(options: [.alert, .sound, .badge]) { [weak self] granted, error in
            DispatchQueue.main.async {
                if let error = error {
                    self?.sendMessageToWeb(type: "notificationError", data: ["error": error.localizedDescription])
                } else {
                    self?.sendMessageToWeb(type: "notificationPermission", data: ["status": granted ? "granted" : "denied"])
                    if granted {
                        UIApplication.shared.registerForRemoteNotifications()
                    }
                }
            }
        }
    }
    
    private func getDeviceToken() {
        if let token = UserDefaults.standard.string(forKey: "deviceToken") {
            sendMessageToWeb(type: "deviceToken", data: ["token": token])
        } else {
            sendMessageToWeb(type: "deviceToken", data: ["token": ""])
        }
    }
    
    private func handleInAppPurchaseRequest(_ data: [String: Any]) {
        guard let action = data["action"] as? String else { return }
        
        switch action {
        case "getProducts":
            if let productIds = data["productIds"] as? [String] {
                fetchProducts(productIds: Set(productIds))
            }
        case "purchase":
            if let productId = data["productId"] as? String {
                purchaseProduct(productId: productId)
            }
        case "restore":
            restorePurchases()
        default:
            break
        }
    }
    
    private func fetchProducts(productIds: Set<String>) {
        guard !productIds.isEmpty else {
            sendMessageToWeb(type: "productsError", data: ["error": "No product IDs provided"])
            return
        }
        
        productRequest = SKProductsRequest(productIdentifiers: productIds)
        productRequest?.delegate = self
        productRequest?.start()
    }
    
    private func purchaseProduct(productId: String) {
        guard SKPaymentQueue.canMakePayments() else {
            sendMessageToWeb(type: "purchaseError", data: ["error": "Payments not allowed"])
            return
        }
        
        guard let product = availableProducts.first(where: { $0.productIdentifier == productId }) else {
            sendMessageToWeb(type: "purchaseError", data: ["error": "Product not found"])
            return
        }
        
        let payment = SKPayment(product: product)
        SKPaymentQueue.default().add(payment)
    }
    
    private func restorePurchases() {
        SKPaymentQueue.default().restoreCompletedTransactions()
    }
    
    private func handleNativeLog(_ data: [String: Any]) {
        if let message = data["message"] as? String,
           let level = data["level"] as? String {
            print("[\(level.uppercased())] WebView: \(message)")
        }
    }
}

extension WebViewController: WKNavigationDelegate {
    func webView(_ webView: WKWebView, decidePolicyFor navigationAction: WKNavigationAction, decisionHandler: @escaping (WKNavigationActionPolicy) -> Void) {
        guard let url = navigationAction.request.url else {
            decisionHandler(.cancel)
            return
        }
        
        let urlString = url.absoluteString
        
        if urlString.hasPrefix("tel:") || urlString.hasPrefix("mailto:") || urlString.hasPrefix("sms:") {
            if UIApplication.shared.canOpenURL(url) {
                UIApplication.shared.open(url, options: [:], completionHandler: nil)
            }
            decisionHandler(.cancel)
            return
        }
        
        if !urlString.hasPrefix(websiteURL) && !urlString.hasPrefix("about:blank") {
            if UIApplication.shared.canOpenURL(url) {
                UIApplication.shared.open(url, options: [:], completionHandler: nil)
            }
            decisionHandler(.cancel)
            return
        }
        
        decisionHandler(.allow)
    }
    
    func webView(_ webView: WKWebView, didFinish navigation: WKNavigation!) {
        progressView.isHidden = true
    }
    
    func webView(_ webView: WKWebView, didFail navigation: WKNavigation!, withError error: Error) {
        progressView.isHidden = true
        showError(message: "Failed to load page: \(error.localizedDescription)")
    }
    
    func webView(_ webView: WKWebView, didFailProvisionalNavigation navigation: WKNavigation!, withError error: Error) {
        progressView.isHidden = true
        showError(message: "Failed to load page: \(error.localizedDescription)")
    }
    
    private func showError(message: String) {
        let alert = UIAlertController(title: "Error", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "Retry", style: .default) { [weak self] _ in
            self?.loadWebsite()
        })
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        present(alert, animated: true)
    }
}

