extension WebViewController: UIImagePickerControllerDelegate, UINavigationControllerDelegate {
    func imagePickerController(_ picker: UIImagePickerController, didFinishPickingMediaWithInfo info: [UIImagePickerController.InfoKey : Any]) {
        picker.dismiss(animated: true)
        
        guard let image = info[.originalImage] as? UIImage else {
            sendMessageToWeb(type: "cameraError", data: ["error": "Failed to get image"])
            return
        }
        
        guard let imageData = image.jpegData(compressionQuality: 0.8) else {
            sendMessageToWeb(type: "cameraError", data: ["error": "Failed to process image"])
            return
        }
        
        let base64String = imageData.base64EncodedString()
        sendMessageToWeb(type: "cameraImage", data: ["image": "data:image/jpeg;base64,\(base64String)"])
    }
    
    func imagePickerControllerDidCancel(_ picker: UIImagePickerController) {
        picker.dismiss(animated: true)
        sendMessageToWeb(type: "cameraCancelled", data: [:])
    }
}

extension WebViewController: SKProductsRequestDelegate {
    func productsRequest(_ request: SKProductsRequest, didReceive response: SKProductsResponse) {
        availableProducts = response.products
        
        let products = response.products.map { product -> [String: Any] in
            return [
                "productId": product.productIdentifier,
                "title": product.localizedTitle,
                "description": product.localizedDescription,
                "price": product.price.stringValue,
                "priceLocale": product.priceLocale.currencyCode ?? "USD"
            ]
        }
        
        sendMessageToWeb(type: "products", data: ["products": products])
    }
    
    func request(_ request: SKRequest, didFailWithError error: Error) {
        sendMessageToWeb(type: "productsError", data: ["error": error.localizedDescription])
    }
}

extension WebViewController: SKPaymentTransactionObserver {
    func paymentQueue(_ queue: SKPaymentQueue, updatedTransactions transactions: [SKPaymentTransaction]) {
        for transaction in transactions {
            switch transaction.transactionState {
            case .purchased:
                handlePurchaseSuccess(transaction: transaction)
                SKPaymentQueue.default().finishTransaction(transaction)
            case .failed:
                handlePurchaseFailure(transaction: transaction)
                SKPaymentQueue.default().finishTransaction(transaction)
            case .restored:
                handlePurchaseRestored(transaction: transaction)
                SKPaymentQueue.default().finishTransaction(transaction)
            case .deferred, .purchasing:
                break
            @unknown default:
                break
            }
        }
    }
    
    private func handlePurchaseSuccess(transaction: SKPaymentTransaction) {
        let data: [String: Any] = [
            "productId": transaction.payment.productIdentifier,
            "transactionId": transaction.transactionIdentifier ?? "",
            "transactionDate": ISO8601DateFormatter().string(from: transaction.transactionDate ?? Date())
        ]
        sendMessageToWeb(type: "purchaseSuccess", data: data)
    }
    
    private func handlePurchaseFailure(transaction: SKPaymentTransaction) {
        let errorMessage = transaction.error?.localizedDescription ?? "Unknown error"
        sendMessageToWeb(type: "purchaseError", data: ["error": errorMessage])
    }
    
    private func handlePurchaseRestored(transaction: SKPaymentTransaction) {
        let data: [String: Any] = [
            "productId": transaction.payment.productIdentifier,
            "transactionId": transaction.transactionIdentifier ?? ""
        ]
        sendMessageToWeb(type: "purchaseRestored", data: data)
    }
    
    func paymentQueueRestoreCompletedTransactionsFinished(_ queue: SKPaymentQueue) {
        sendMessageToWeb(type: "restoreComplete", data: [:])
    }
    
    func paymentQueue(_ queue: SKPaymentQueue, restoreCompletedTransactionsFailedWithError error: Error) {
        sendMessageToWeb(type: "restoreError", data: ["error": error.localizedDescription])
    }
}